INSERT INTO "Store" ("id", "slug", "name", "createdAt", "updatedAt")
VALUES (
    '4e5db5c0-0cc8-4e6a-8d40-cc5ce5131c13',
    'arcane-fortress',
    'Arcane Fortress',
    CURRENT_TIMESTAMP,
    CURRENT_TIMESTAMP
)
ON CONFLICT ("slug") DO UPDATE
SET
